            </Button>
            <Button
              variant="ghost"
              size="sm"
              onClick={toggleTheme}
              className="rounded-full p-2"
            >
              {theme === 'light' ? <Icons.Moon className="w-4 h-4" /> : <Icons.Sun className="w-4 h-4" />}
            </Button>
          </div>
        </nav>
        {/* Main Content Area */}
        <main className="flex-1 relative overflow-hidden">
