                <CharacterGallery />
              </div>
            )}
            {activeSpace === 'Storyboard' && (
              <div className="h-full">
                <StoryboardSpace />
              </div>
            )}
            {activeSpace === 'Editor' && (
              <div className="h-full">
                <EditorSpace />
              </div>
            )}
          </div>
        </main>
        {/* Collapsible Islands */}
        <SidebarIsland />
        <AIAssistantIsland />
      </div>
    </div>
  );
};
