    (function mount(){
      const { createRoot } = ReactDOM;
      const root = createRoot(document.getElementById('root'));
      // prefer a single Providers wrapper if app.js exposes it; otherwise
      // fall back to individual providers or identity fragments to preserve behavior
      const Providers = window.Providers || (function FallbackProviders({children}){
        const ThemeProvider = window.ThemeProvider || (({children})=>children);
        const CollapsibleProvider = window.CollapsibleProvider || (({children})=>children);
        const AppProvider = window.AppProvider || (({children})=>children);
        return (
          <ThemeProvider>
            <CollapsibleProvider>
              <AppProvider>{children}</AppProvider>
            </CollapsibleProvider>
          </ThemeProvider>
        );
      });
      // Simple query-based routing:
      // - ?app  -> render the full App exported by app.js (if present on window)
      // - ?tab=projects -> render ProjectsPage
      // - default -> render DashboardUI
      const params = new URLSearchParams(window.location.search);
      const activeTab = params.get('tab');
      const mountApp = params.has('app');
      // prefer App component exported by app.js if available
      const AppComponent = window.App || null;
      function AppShell(){
        return (
          <Providers>
            {/* Left compact sidebar (defined above) — hide when mounting the full `?app` UI */}
            {!mountApp && <Sidebar />}
            {mountApp ? (
              AppComponent ? <AppComponent /> : <div style={{padding:20}}>App module not loaded — ensure app.js is present and defines `App` on window</div>
            ) : (
              activeTab === 'projects' ? <ProjectsPage /> : <DashboardUI />
            )}
            {/* Global modals (templates, notifications, header) must be present in DOM for toggles to work */}
            <Modals />
          </Providers>
        );
      }
      root.render(<AppShell />);
      setTimeout(()=>{ if(window.anime) window.anime({ targets: '.animate-slide-down', translateY: [-20,0], opacity: [0,1], duration: 800, easing: 'easeOutCubic' }); },100);
    })();
  </script>
</body>
</html>/* Tailwind CSS Integration for NarratingOS */
@tailwind base;
@tailwind components;
@tailwind utilities;
@layer base {
  :root {
    /* Light theme colors */
    --background: 0 0% 100%;
    --foreground: 240 10% 3.9%;
    --card: 0 0% 100%;
    --card-foreground: 240 10% 3.9%;
    --popover: 0 0% 100%;
    --popover-foreground: 240 10% 3.9%;
    --primary: 221 83% 53%;
    --primary-foreground: 0 0% 98%;
    --secondary: 240 4.8% 95.9%;
    --secondary-foreground: 240 5.9% 10%;
    --muted: 240 4.8% 95.9%;
    --muted-foreground: 240 3.8% 46.1%;
    --accent: 240 4.8% 95.9%;
    --accent-foreground: 240 5.9% 10%;
    --destructive: 0 84.2% 60.2%;
    --destructive-foreground: 0 0% 98%;
    --border: 240 5.9% 90%;
    --input: 240 5.9% 90%;
    --ring: 221 83% 53%;
    --radius: 0.5rem;
  }
  .dark {
    /* Dark theme colors */
    --background: 240 10% 3.9%;
    --foreground: 0 0% 98%;
    --card: 240 10% 3.9%;
    --card-foreground: 0 0% 98%;
    --popover: 240 10% 3.9%;
    --popover-foreground: 0 0% 98%;
    --primary: 217 91% 60%;
    --primary-foreground: 0 0% 98%;
    --secondary: 240 3.7% 15.9%;
    --secondary-foreground: 0 0% 98%;
    --muted: 240 3.7% 15.9%;
    --muted-foreground: 240 5% 64.9%;
    --accent: 240 3.7% 15.9%;
    --accent-foreground: 0 0% 98%;
    --destructive: 0 62.8% 30.6%;
    --destructive-foreground: 0 0% 98%;
    --border: 240 3.7% 15.9%;
    --input: 240 3.7% 15.9%;
    --ring: 217 91% 60%;
  }
  * {
    @apply border-border;
  }
  body {
    @apply bg-background text-foreground font-sans antialiased;
  }
}
@layer components {
  /* Story Card Component */
  .story-card {
    @apply bg-card border border-border rounded-lg p-4 cursor-pointer overflow-hidden;
    @apply transition-all duration-300 ease-out;
  }
  .story-card:hover {
    @apply shadow-md transform -translate-y-0.5;
  }
  /* Progress Bar Component */
  .progress-bar {
    @apply w-full h-1 bg-muted rounded-full overflow-hidden;
  }
  .progress-fill {
    @apply h-full bg-primary transition-all duration-300 ease-in-out;
  }
  /* Button Components */
  .btn {
    @apply inline-flex items-center justify-center px-4 py-2 rounded-md text-sm font-medium;
    @apply transition-all duration-150 ease-in-out cursor-pointer border-0 no-underline;
  }
  .btn-primary {
    @apply bg-primary text-primary-foreground hover:bg-primary/90;
  }
  .btn-secondary {
    @apply bg-secondary text-secondary-foreground hover:bg-secondary/80;
  }
  .btn-ghost {
    @apply bg-transparent text-foreground hover:bg-accent hover:text-accent-foreground;
  }
  /* Card Component */
  .card {
    @apply bg-card text-card-foreground border border-border rounded-lg p-6 shadow-sm;
  }
  /* Input Components */
  .input {
    @apply w-full px-3 py-2 border border-input rounded-md bg-background text-foreground text-sm;
    @apply transition-colors duration-150 ease-in-out;
    @apply focus:outline-none focus:ring-2 focus:ring-ring focus:border-ring;
  }
  .textarea {
    @apply resize-y min-h-10 px-3 py-2 border border-input rounded-md bg-background text-foreground text-sm;
    @apply transition-colors duration-150 ease-in-out leading-relaxed;
    @apply focus:outline-none focus:ring-2 focus:ring-ring focus:border-ring;
  }
  /* Navigation Components */
  .nav-link {
    @apply px-3 py-2 rounded-md text-sm font-medium transition-all duration-150 ease-in-out;
    @apply cursor-pointer border-0 bg-transparent text-foreground no-underline;
    @apply hover:bg-accent hover:text-accent-foreground;
  }
  .nav-link.active {
    @apply bg-primary text-primary-foreground;
  }
  /* AI Suggestion Component */
  .ai-suggestion {
    @apply p-3 bg-background border border-border rounded-md text-sm transition-all duration-150 ease-in-out cursor-pointer;
    @apply hover:bg-accent;
  }
  /* Character Card Component */
  .character-card {
    @apply transition-all duration-300 ease-out;
    @apply hover:scale-105;
  }
  .card-hover {
    @apply transition-all duration-300 ease-out;
    @apply hover:-translate-y-1 hover:shadow-lg;
  }
  .button-press {
    @apply transition-all duration-150 ease-out;
    @apply active:scale-95;
  }
}
@layer utilities {
  /* Animation utilities */
  .animate-slide-up {
    animation: slideInUp 0.4s cubic-bezier(0.4, 0, 0.2, 1);
  }
  .animate-slide-right {
    animation: slideInRight 0.4s cubic-bezier(0.4, 0, 0.2, 1);
  }
  .animate-slide-left {
    animation: slideInLeft 0.4s cubic-bezier(0.4, 0, 0.2, 1);
  }
  .animate-fade-in {
    animation: fadeIn 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  }
  .animate-scale-in {
    animation: scaleIn 0.3s cubic-bezier(0.68, -0.55, 0.265, 1.55);
  }
  .animate-bounce {
    animation: bounce 1s infinite;
  }
  /* Scrollbar utilities */
  .scrollbar-thin::-webkit-scrollbar {
    @apply w-2 h-2;
  }
  .scrollbar-thin::-webkit-scrollbar-track {
    @apply bg-muted rounded;
  }
  .scrollbar-thin::-webkit-scrollbar-thumb {
    @apply bg-border rounded;
  }
  .scrollbar-thin::-webkit-scrollbar-thumb:hover {
    @apply bg-muted-foreground;
  }
  /* Loading utilities */
  .loading-shimmer {
    background: linear-gradient(90deg, hsl(var(--muted)) 25%, hsl(var(--accent)) 50%, hsl(var(--muted)) 75%);
    background-size: 200px 100%;
    animation: shimmer 1.5s infinite;
  }
  /* Tooltip utilities */
  .tooltip::after {
    content: attr(data-tooltip);
    @apply absolute bottom-full left-1/2 transform -translate-x-1/2;
    @apply bg-popover text-popover-foreground px-3 py-2 rounded-md text-sm whitespace-nowrap;
    @apply opacity-0 pointer-events-none transition-opacity duration-200;
    @apply shadow-md border border-border z-50;
  }
  .tooltip:hover::after {
    @apply opacity-100;
  }
  /* Collapsible Island Animations */
  .island-slide-up {
    animation: islandSlideUp 0.5s ease-out;
  }
  .island-slide-down {
    animation: islandSlideDown 0.5s ease-out;
  }
  .island-expand {
    animation: islandExpand 0.3s ease-out;
  }
  .island-collapse {
    animation: islandCollapse 0.3s ease-out;
  }
}
/* Animation keyframes */
@keyframes slideInUp {
  from {
    opacity: 0;
    transform: translate3d(0, 30px, 0);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0);
  }
}
@keyframes slideInRight {
  from {
    opacity: 0;
    transform: translate3d(30px, 0, 0);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0);
  }
}
@keyframes slideInLeft {
  from {
    opacity: 0;
    transform: translate3d(-30px, 0, 0);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0);
  }
}
@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}
@keyframes scaleIn {
  from {
    opacity: 0;
    transform: scale(0.9);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}
@keyframes bounce {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-10px); }
}
@keyframes shimmer {
  0% { background-position: -200px 0; }
  100% { background-position: calc(200px + 100%) 0; }
}
/* Character relationship web styles */
.character-web {
  @apply relative min-h-96;
}
.character-node {
  @apply absolute w-20 h-20 rounded-full bg-primary text-primary-foreground;
  @apply flex items-center justify-center text-sm font-semibold cursor-pointer;
  @apply transition-all duration-300 ease-out shadow-md;
}
.character-node:hover {
  @apply scale-110 shadow-lg;
}
.character-node.selected {
  @apply bg-accent scale-115;
  box-shadow: 0 0 0 4px rgba(16, 185, 129, 0.3);
}
.relationship-line {
  @apply absolute h-0.5 bg-border transition-all duration-300 ease-out;
  transform-origin: left center;
}
.relationship-line:hover,
.relationship-line.active {
  @apply bg-primary h-1;
}
/* Storyboard styles */
.storyboard-scene {
  @apply transition-all duration-300 ease-out cursor-pointer;
}
.storyboard-scene:hover {
  @apply scale-105 shadow-md;
}
.storyboard-scene.dragging {
  @apply rotate-6 scale-105 opacity-80 z-50;
}
/* Timeline editor styles */
.timeline-track {
  @apply relative min-h-15 bg-muted rounded-lg mb-2 transition-all duration-200;
}
.timeline-track:hover {
  @apply bg-accent;
}
.timeline-clip {
  @apply absolute h-12 bg-primary rounded-md cursor-pointer;
  @apply transition-all duration-200 border-2 border-transparent;
}
.timeline-clip:hover {
  @apply border-accent scale-105;
}
.timeline-clip.selected {
  @apply border-accent;
  box-shadow: 0 0 0 3px rgba(16, 185, 129, 0.3);
}
/* Dark mode enhancements */
.dark .ql-editor {
  @apply bg-card text-card-foreground border-border;
}
.dark .ql-toolbar {
  @apply bg-muted border-border;
}
.dark .ql-toolbar .ql-stroke {
  stroke: hsl(var(--muted-foreground)) !important;
}
.dark .ql-toolbar .ql-fill {
  fill: hsl(var(--muted-foreground)) !important;
}
.dark .ql-toolbar .ql-picker-label {
  @apply text-muted-foreground;
}
.dark input[type="text"],
.dark input[type="email"],
.dark textarea,
.dark select {
  @apply bg-input text-foreground border-border;
}
.dark input[type="text"]:focus,
.dark input[type="email"]:focus,
.dark textarea:focus,
.dark select:focus {
  @apply border-ring ring-2 ring-ring;
}
.dark ::selection {
  @apply bg-primary text-primary-foreground;
}
.dark .card-hover:hover {
  box-shadow: 0 8px 25px -5px rgba(0, 0, 0, 0.3), 0 4px 6px -2px rgba(0, 0, 0, 0.2);
}
.dark .tooltip::after {
  @apply bg-popover text-popover-foreground border-border;
  box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.3);
}
/* Custom components */
.story-card {
  background-color: var(--card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 1rem;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  cursor: pointer;
  overflow: hidden;
}
.story-card:hover {
  box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1);
  transform: translateY(-2px);
}
/* Enhanced collapsible animations */
.story-card .collapsible-content {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  will-change: max-height, opacity, transform;
}
.story-card .collapsible-content.collapsed {
  max-height: 0 !important;
  opacity: 0;
  transform: scaleY(0);
  margin-top: 0;
  padding-top: 0;
  pointer-events: none;
}
.story-card .collapsible-content.expanded {
  max-height: 300px;
  opacity: 1;
  transform: scaleY(1);
  margin-top: 1rem;
}
/* Collapse toggle button animations */
.collapse-toggle {
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
  border-radius: 0.375rem;
}
.collapse-toggle:hover {
  background-color: var(--muted);
  transform: scale(1.05);
}
.collapse-toggle svg {
  transition: transform 0.2s cubic-bezier(0.4, 0, 0.2, 1);
}
/* Interactive element animations */
.interactive {
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
}
.interactive:hover {
  transform: scale(1.02);
  background-color: var(--accent);
}
.interactive:active {
  transform: scale(0.98);
}
.story-cover {
  width: 100%;
  height: 200px;
  object-fit: cover;
  border-radius: calc(var(--radius) - 2px);
  margin-bottom: 0.75rem;
}
.progress-bar {
  width: 100%;
  height: 4px;
  background-color: var(--muted);
  border-radius: 2px;
  overflow: hidden;
}
.progress-fill {
  height: 100%;
  background-color: var(--primary);
  transition: width 0.3s ease-in-out;
}
/* Navigation */
.nav-link {
  padding: 0.5rem 0.75rem;
  border-radius: calc(var(--radius) - 2px);
  font-size: 0.875rem;
  font-weight: 500;
  transition: all 0.2s ease-in-out;
  cursor: pointer;
  border: none;
  background: transparent;
  color: var(--foreground);
  text-decoration: none;
}
.nav-link:hover {
  background-color: var(--accent);
  color: var(--accent-foreground);
}
.nav-link.active {
  background-color: var(--primary);
  color: var(--primary-foreground);
}
/* Sidebar */
.sidebar {
  transform: translateX(-100%);
  transition: transform 0.3s ease-in-out;
}
.sidebar.open {
  transform: translateX(0);
}
@media (min-width: 768px) {
  .sidebar {
    transform: translateX(0);
  }
}
/* AI Assistant styles */
.ai-suggestion {
  padding: 0.75rem;
  background-color: var(--background);
  border: 1px solid var(--border);
  border-radius: calc(var(--radius) - 2px);
  font-size: 0.875rem;
  transition: all 0.2s ease-in-out;
  cursor: pointer;
}
.ai-suggestion:hover {
  background-color: var(--accent);
}
/* Character card animations */
.character-card {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}
.character-card:hover {
  transform: scale(1.02);
}
/* Smooth scrollbars */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}
::-webkit-scrollbar-track {
  background: var(--muted);
  border-radius: 4px;
}
::-webkit-scrollbar-thumb {
  background: var(--border);
  border-radius: 4px;
}
::-webkit-scrollbar-thumb:hover {
  background: var(--muted-foreground);
}
/* === Enhanced Animations and Micro-interactions === */
/* Animation keyframes */
@keyframes slideInUp {
  from {
    opacity: 0;
    transform: translate3d(0, 30px, 0);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0);
  }
}
@keyframes slideInRight {
  from {
    opacity: 0;
    transform: translate3d(30px, 0, 0);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0);
  }
}
@keyframes slideInLeft {
  from {
    opacity: 0;
    transform: translate3d(-30px, 0, 0);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0);
  }
}
@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}
@keyframes scaleIn {
  from {
    opacity: 0;
    transform: scale(0.9);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}
@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.7; }
}
@keyframes shimmer {
  0% { background-position: -200px 0; }
  100% { background-position: calc(200px + 100%) 0; }
}
@keyframes bounce {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-10px); }
}
/* Animation classes */
.animate-slide-up { animation: slideInUp 0.4s cubic-bezier(0.4, 0, 0.2, 1); }
.animate-slide-right { animation: slideInRight 0.4s cubic-bezier(0.4, 0, 0.2, 1); }
.animate-slide-left { animation: slideInLeft 0.4s cubic-bezier(0.4, 0, 0.2, 1); }
.animate-fade-in { animation: fadeIn 0.3s cubic-bezier(0.4, 0, 0.2, 1); }
.animate-scale-in { animation: scaleIn 0.3s cubic-bezier(0.68, -0.55, 0.265, 1.55); }
.animate-pulse { animation: pulse 2s infinite; }
.animate-bounce { animation: bounce 1s infinite; }
/* Micro-interactions */
.interactive {
  transition: all 0.15s ease-out;
  cursor: pointer;
}
.interactive:hover {
  transform: translateY(-1px);
}
.interactive:active {
  transform: translateY(0);
}
.card-hover {
  transition: all 0.3s ease-out;
}
.card-hover:hover {
  transform: translateY(-4px);
  box-shadow: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04);
}
.button-press {
  transition: all 0.15s ease-out;
}
.button-press:active {
  transform: scale(0.98);
}
/* Loading states */
.loading-shimmer {
  background: linear-gradient(90deg, var(--muted) 25%, var(--accent) 50%, var(--muted) 75%);
  background-size: 200px 100%;
  animation: shimmer 1.5s infinite;
}
/* Enhanced story grid animations */
.story-grid {
  display: grid;
  gap: 1.5rem;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
}
.story-card {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  transform-origin: center bottom;
}
.story-card:hover {
  transform: translateY(-8px) scale(1.02);
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.25);
}
/* Character relationship web styles */
.character-web {
  position: relative;
  min-height: 400px;
}
.character-node {
  position: absolute;
  width: 80px;
  height: 80px;
  border-radius: 50%;
  background: var(--primary);
  color: var(--primary-foreground);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.8rem;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
}
.character-node:hover {
  transform: scale(1.1);
  box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1);
}
.character-node.selected {
  background: var(--accent);
  transform: scale(1.15);
  box-shadow: 0 0 0 4px rgba(16, 185, 129, 0.3);
}
.relationship-line {
  position: absolute;
  height: 2px;
  background: var(--border);
  transform-origin: left center;
  transition: all 0.3s ease;
}
.relationship-line:hover,
.relationship-line.active {
  background: var(--primary);
  height: 3px;
}
/* Enhanced storyboard features */
.storyboard-scene {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  cursor: pointer;
}
.storyboard-scene:hover {
  transform: scale(1.03);
  box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1);
}
.storyboard-scene.dragging {
  transform: rotate(5deg) scale(1.05);
  opacity: 0.8;
  z-index: 1000;
}
/* Timeline editor styles */
.timeline-track {
  position: relative;
  min-height: 60px;
  background: var(--muted);
  border-radius: 8px;
  margin-bottom: 8px;
  transition: all 0.2s ease;
}
.timeline-track:hover {
  background: var(--accent);
}
.timeline-clip {
  position: absolute;
  height: 50px;
  background: var(--primary);
  border-radius: 6px;
  cursor: pointer;
  transition: all 0.2s ease;
  border: 2px solid transparent;
}
.timeline-clip:hover {
  border-color: var(--accent);
  transform: scale(1.02);
}
.timeline-clip.selected {
  border-color: var(--accent);
  box-shadow: 0 0 0 3px rgba(16, 185, 129, 0.3);
}
/* Progress ring animation */
.progress-ring {
  transition: stroke-dashoffset 0.5s ease-in-out;
}
/* Enhanced AI assistant */
.ai-message {
  animation: slideInLeft 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}
.ai-message:nth-child(even) {
  animation: slideInRight 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}
.ai-typing {
  display: inline-block;
}
.ai-typing span {
  display: inline-block;
  animation: pulse 1.4s infinite;
}
.ai-typing span:nth-child(2) {
  animation-delay: 0.2s;
}
.ai-typing span:nth-child(3) {
  animation-delay: 0.4s;
}
/* Enhanced responsive breakpoints */
@media (max-width: 768px) {
  .story-grid {
    grid-template-columns: 1fr;
  }
  .character-node {
    width: 60px;
    height: 60px;
    font-size: 0.7rem;
  }
  .timeline-clip {
    height: 40px;
  }
}
/* Rich text editor enhancements */
.ql-editor {
  font-size: 16px;
  line-height: 1.8;
  padding: 2rem;
}
.ql-editor:focus {
  outline: none;
}
.ql-toolbar {
  border-top: 1px solid var(--border);
  border-left: 1px solid var(--border);
  border-right: 1px solid var(--border);
}
.ql-container {
  border-bottom: 1px solid var(--border);
  border-left: 1px solid var(--border);
  border-right: 1px solid var(--border);
}
/* Drag and drop visual feedback */
.drag-over {
  background: rgba(16, 185, 129, 0.1);
  border: 2px dashed var(--accent);
}
.drop-zone {
  min-height: 100px;
  border: 2px dashed var(--border);
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--muted-foreground);
  transition: all 0.3s ease;
}
.drop-zone.active {
  border-color: var(--accent);
  background: rgba(16, 185, 129, 0.05);
  color: var(--accent);
}
/* Enhanced tooltips */
.tooltip {
  position: relative;
}
.tooltip::after {
  content: attr(data-tooltip);
  position: absolute;
  bottom: 100%;
  left: 50%;
  transform: translateX(-50%);
  background: var(--card);
  color: var(--card-foreground);
  padding: 8px 12px;
  border-radius: 6px;
  font-size: 0.875rem;
  white-space: nowrap;
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.2s ease;
  box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
  z-index: 1000;
}
.tooltip:hover::after {
  opacity: 1;
}
/* Enhanced Dark Mode Styles */
.dark {
  color-scheme: dark;
}
.dark .ql-editor {
  background-color: var(--card) !important;
  color: var(--card-foreground) !important;
  border-color: var(--border) !important;
}
.dark .ql-toolbar {
  background-color: var(--muted) !important;
  border-color: var(--border) !important;
}
.dark .ql-toolbar .ql-stroke {
  stroke: var(--muted-foreground) !important;
}
.dark .ql-toolbar .ql-fill {
  fill: var(--muted-foreground) !important;
}
.dark .ql-toolbar .ql-picker-label {
  color: var(--muted-foreground) !important;
}
.dark input[type="text"],
.dark input[type="email"],
.dark textarea,
.dark select {
  background-color: var(--input) !important;
  color: var(--foreground) !important;
  border-color: var(--border) !important;
}
.dark input[type="text"]:focus,
.dark input[type="email"]:focus,
.dark textarea:focus,
.dark select:focus {
  border-color: var(--ring) !important;
  box-shadow: 0 0 0 2px var(--ring) !important;
}
/* Dark mode scrollbar */
.dark ::-webkit-scrollbar {
  width: 8px;
}
.dark ::-webkit-scrollbar-track {
  background: var(--muted);
}
.dark ::-webkit-scrollbar-thumb {
  background: var(--muted-foreground);
  border-radius: 4px;
}
.dark ::-webkit-scrollbar-thumb:hover {
  background: var(--foreground);
}
/* Dark mode selection */
.dark ::selection {
  background-color: var(--primary);
  color: var(--primary-foreground);
}
/* Enhanced dark mode animations */
/* Collapsible Island Animations */
@keyframes islandSlideUp {
  from {
    opacity: 0;
    transform: translateY(100px) scale(0.95);
  }
  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}
@keyframes islandSlideDown {
  from {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
  to {
    opacity: 0;
    transform: translateY(100px) scale(0.95);
  }
}
@keyframes islandExpand {
  from {
    max-height: 60px;
    opacity: 0.8;
  }
  to {
    max-height: 80vh;
    opacity: 1;
  }
}
@keyframes islandCollapse {
  from {
    max-height: 80vh;
    opacity: 1;
  }
  to {
    max-height: 60px;
    opacity: 0.8;
  }
}
.dark .card-hover:hover {
  box-shadow: 0 8px 25px -5px rgba(0, 0, 0, 0.3), 0 4px 6px -2px rgba(0, 0, 0, 0.2);
}
.dark .interactive:hover {
  background-color: var(--accent) !important;
  transform: scale(1.02);
}
/* Dark mode for tooltips */
.dark .tooltip::after {
  background-color: var(--popover);
  color: var(--popover-foreground);
  border: 1px solid var(--border);
  box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.3);
}# NARRATING OS App Concept Discussion
*August 30, 2025*

## App Structure Overview
The application is conceptualized in three distinct but interconnected creative spaces:

1. **Writing Space** (Ideation & Development)
2. **Storyboard Space** (Visualization & Planning)
3. **Film Editor Space** (Production Planning & Assembly)

## Organizational Structure: Spaces
- Spaces function as hierarchical folders for specific stories
- Structure flows from plots to subplots
- Supports both small projects and complex narratives (movies, series)
- Version history tracks at the subplot level

### Enhanced Space Structure Features
- Support for different narrative structures (linear, nonlinear, multi-POV, etc.)
- AI-suggested content ratings based on themes and content
- Timeline position tagging for nonlinear narratives
- Relationship indicators between related story elements

## Phase 1: Writing Space

### Key UI Elements (Wattpad-inspired):
- Distraction-free writing interface
- Chapter-based organization
- Story dashboard with analytics
- Progress indicators for plot points

### Specific Features:
1. **Story Library View**
   - Grid of story "spaces" with cover images and progress indicators
   - Quick-access tags for genre and status
   - Sorting options (recent, title, completion percentage)

2. **Writing Canvas**
   - Minimalist interface with full-screen option
   - Collapsible right-sidebar for AI assistance
   - Left-sidebar for plot/subplot navigation
   - Auto-save with visual indicators

3. **Character Gallery**
   - Character cards with expandable details
   - Relationship web visualization
   - Character development tracking

4. **Inline AI Assistance**
   - Contextual suggestions
   - Question prompts in margins

## Phase 2: Storyboard Space

### Key UI Elements:
- Visual storytelling focus
- Scene navigation similar to chapter navigation

### Specific Features:
1. **Storyboard Gallery**
   - Visual grid/timeline view of scenes
   - Thumbnail previews with scene information
   - Drag-and-drop reordering

2. **Scene Detail View**
   - Split view with script and storyboard visualization
   - Character position markers and camera angles
   - Mood board integration

3. **Asset Library**
   - Character design sheets
   - Location reference galleries
   - Props and elements library

## Phase 3: Film Editor Space

### Key UI Elements:
- Timeline-based navigation
- Scene organization adapted from chapter management

### Specific Features:
1. **Timeline Editor**
   - Visual timeline with color-coded scene blocks
   - Expandable scenes showing shots
   - Drag-and-drop interface

2. **Shot Manager**
   - Grid view of shots within scenes
   - Technical details panel
   - Storyboard reference connection

3. **Post-Production Dashboard**
   - Task lists for various post-production aspects
   - Progress tracking
   - Feedback and notes system

## Cross-Phase Elements:
- Consistent navigation bar across phases
- Smooth transitions between writing, storyboarding, and editing
- Universal profile & settings access
- Persistent AI assistant button

## AI Assistance System

### AI-Guided Questioning Approach
- AI functions as a guide rather than generator
- Asks targeted questions based on storytelling principles
- Helps users uncover their own creative solutions
- Maintains user ownership of all creative content

### AI Assistance per Phase
1. **Writing Phase AI**
   - Structure suggestions based on selected storytelling frameworks (Hero's Journey, Save the Cat, etc.)
   - Character development questionnaires to build depth
   - World-building prompts to ensure consistency
   - Theme exploration through guided questions

2. **Storyboard Phase AI**
   - Visual consistency checks between scenes
   - Shot suggestion based on narrative importance
   - Reference image suggestions for mood/tone
   - Character positioning advice for dramatic effect

3. **Film Editor Phase AI**
   - Pacing analysis and suggestions
   - Scene transition recommendations
   - Music mood suggestions aligned with emotional beats
   - Technical requirement alerts (e.g., VFX needs, sound design opportunities)

### AI Feedback Systems
- Visual progress indicators for story elements
- Rating system for plot coherence, character depth
- Gap analysis to identify underdeveloped areas
- Suggestion panels that never override user content

## User Flow Between Phases

### Phase 1 → Phase 2 Transition
- Writing elements can be "sent to storyboard" via context menu
- Automatic scene detection from written content
- Character descriptions generate visual reference suggestions
- Setting/location descriptions form visual mood boards

### Phase 2 → Phase 3 Transition
- Complete storyboards generate initial timeline structure
- Shot lists and scene breakdowns feed into editing plan
- Visual assets link directly to timeline elements
- Technical notes from storyboard phase appear in editor

## Role-to-Module Integration
Based on the film industry roles from the PRD, each role maps to specific features within our three-phase system:

1. **Creative Development Roles**
   - Storywriter → Writing Space
   - Scriptwriter → Writing Space (scriptwriting feature)
   - Character Builder → Writing Space (character gallery)
   - World Builder → Writing Space (world-building tools)

2. **Production Planning Roles**
   - Director → Storyboard Space (scene planning)
   - DoP → Storyboard Space (visual styling)
   - Production Designer → Storyboard Space (set elements)
   - Costume Designer → Storyboard Space (character visuals)

3. **Post-Production Roles**
   - Editor → Film Editor Space (timeline editor)
   - Sound Designer → Film Editor Space (audio planning)
   - VFX Artist → Film Editor Space (effects planning)
   - Colorist → Film Editor Space (visual tone tools)

## Knowledge Base Integration

The app will incorporate specialized knowledge bases to assist users in each phase:

1. **Writing Knowledge Base**
   - Story structures (Hero's Journey, Three-Act Structure, etc.)
   - Character archetypes and development guides
   - Genre conventions and tropes
   - Dialogue writing resources

2. **Visual Knowledge Base**
   - Shot types and composition guides
   - Visual storytelling principles
   - Color theory and mood references
   - Camera movement techniques

3. **Production Knowledge Base**
   - Editing rhythm and pacing guides
   - Sound design principles
   - Visual effects categories and requirements
   - Color grading approaches

## Visual Analytics and Progress Tracking

The app provides various visualizations to help users track progress and quality:

1. **Story Health Dashboard**
   - Overall completion percentage across all elements
   - Balanced element visualization (character, plot, theme, world)
   - Consistency score across narrative elements
   - Historical progress chart showing work over time

2. **Character Depth Analysis**
   - Character arc visualization showing emotional journey
   - Relationship strength indicators between characters
   - Dialogue distribution among characters
   - Agency score (how much characters drive the plot)

3. **Narrative Structure Visualization**
   - Plot tension graph showing rising and falling action
   - Scene purpose breakdown (exposition, conflict, resolution)
   - Theme presence heat map across scenes
   - Subplot density and distribution

4. **Production Readiness Metrics**
   - Completeness of technical requirements
   - Visual consistency score across storyboards
   - Budget impact estimation based on complexity
   - Resource allocation visualization

## User Customization Options

The application allows for significant personalization:

1. **Interface Layout Options**
   - Light/dark/custom color themes
   - Compact vs. expanded workspace views
   - Focus mode to hide non-essential elements
   - Custom shortcut configuration

2. **AI Assistant Personalization**
   - Adjust questioning style (detailed vs. concise)
   - Focus areas (character, plot, theme, technical)
   - Reference preferences (film, literature, genre)
   - Feedback style customization

3. **Storytelling Approach Templates**
   - Genre-specific workspaces (romance, action, horror, etc.)
   - Structure templates (linear, non-linear, episodic)
   - Audience targeting (age groups, markets)
   - Cultural context settings for diverse storytelling

## Export and Integration

The app supports various export formats and external integrations:

1. **Export Options**
   - Script formats (Final Draft, Fountain, PDF)
   - Storyboard exports (PDF, image sequence)
   - Shot list documentation (CSV, PDF)
   - Project bible/documentation generation

2. **Integration Possibilities**
   - Video editing software (Premiere Pro, Final Cut, DaVinci)
   - Production management tools (Yamdu, StudioBinder)
   - Collaborative platforms (Frame.io, Miro)
   - Asset management systems# NARRATING OS — Finalized Discussion & Improvement Outline

Brief: Record of finalized UI decisions and the ordered plan to implement improvements so we proceed one-by-one without drifting.

High-level plan
- Capture the improvements discussed so far.
- Proceed one-by-one starting with Hierarchical Organization Structure.
- Track decisions, open questions, and next actions here.

Checklist (requirements to address, visible during the process)
- [ ] Hierarchical Organization Structure (stories, plots, subplots)
- [ ] Navigation Breadcrumbs
- [ ] Knowledge Base / Templates integration
- [ ] Story Health Dashboard and analytics
- [ ] Version History & Comparison tools
- [ ] Screen estate optimizations per space (Writing, Storyboard, Editor)
- [ ] Contextual / inline AI suggestions and assistant integration
- [ ] Improved navigation (tabs + hierarchical explorer + breadcrumbs)
- [ ] Multi-user collaboration and presence indicators
- [ ] Microinteractions and animation hooks for key actions
- [ ] Export, integrations, and mobile responsiveness

Finalized improvements (summary of agreed suggestions)

1) Missing Elements from PRD
- Hierarchical project organization (project > plots > acts > scenes)
- Breadcrumb navigation
- Integrated knowledge base (story templates, shot guides, production notes)
- Story health dashboard (character depth, plot tension, coherence, readiness)
- Version history with compare & restore

2) Screen estate & layout improvements (per space)
- Writing Space: wide central editor, collapsible project explorer left, collapsible AI assistant right, collapsible character panel bottom
- Storyboard Space: scene list left, canvas center, asset library right
- Editor Space: media browser left, timeline center, post-production tasks right

3) Key UX recommendations
- Spatial continuity across spaces (visual connectors / content morphing)
- Inline, contextual AI suggestions (not only in sidebar)
- Dual navigation (vertical project explorer + horizontal top tabs)
- Collaboration indicators and commenting/chat

4) Microinteractions & animations
- Transitions between spaces with content morphing
- Auto-save pulse, AI "thinking" indicator, drag-snap animations, progress milestones

5) Final high-level priorities
- Priority A: Content hierarchy (project explorer, breadcrumbs, context persistence)
- Priority B: Contextual AI integration (inline suggestions, rating, apply actions)
- Priority C: Story health & analytics dashboard
- Priority D: Version history & collaboration features

Conversation decisions / next step
- We will work sequentially on improvements to avoid overwhelm.
- START: Hierarchical Organization Structure is selected as the first topic to design and implement.

Open questions to preserve for later review
- What default project templates should be offered at onboarding? (user input required)
- Inline vs assistant-only AI suggestion preference? (user input required)
- Visualization style preference for story health metrics? (user input required)
- Which third-party integrations to prioritize for MVP? (user input required)
- Which features to limit in mobile? (user input required)

Notes
- This file is the single source of truth for finalized UI decisions. As we complete each item, mark the checklist and record decisions and mockups beneath the relevant section.

