// Enhanced AI Assistant Component with Categorized Suggestions
const AIAssistant = () => {
  const { aiAssistantOpen, setAiAssistantOpen } = useApp();
  const [selectedSuggestion, setSelectedSuggestion] = useState(null);
  const [activeCategory, setActiveCategory] = useState('all');
  const [isTyping, setIsTyping] = useState(false);

  const categories = [
    { id: 'all', label: 'All', icon: 'Grid' },
    { id: 'Character Development', label: 'Characters', icon: 'Users' },
    { id: 'Plot Development', label: 'Plot', icon: 'BookOpen' },
    { id: 'World Building', label: 'World', icon: 'Globe' },
    { id: 'Dialogue', label: 'Dialogue', icon: 'MessageCircle' }
  ];

  const filteredSuggestions = activeCategory === 'all' 
    ? mockAISuggestions 
    : mockAISuggestions.filter(s => s.category === activeCategory);

  const handleSuggestionClick = (suggestion) => {
    setSelectedSuggestion(suggestion);
    setIsTyping(true);
    setTimeout(() => setIsTyping(false), 2000);
  };

  if (!aiAssistantOpen) {
    return (
      <button 
        className="fixed right-4 top-20 w-12 h-12 bg-primary text-primary-foreground rounded-full flex items-center justify-center cursor-pointer select-none transition-all duration-200 hover:scale-105 active:scale-95 animate-bounce"
        onClick={() => setAiAssistantOpen(true)}
      >
        <Icons.Zap />
      </button>
    );
  }

  return (
    <div className="w-80 border-l bg-muted/30 flex flex-col animate-slide-left">
      <div className="p-4 border-b">
        <div className="flex items-center justify-between">
          <h3 className="font-semibold flex items-center">
            <Icons.Zap />
            <span className="ml-2">AI Writing Assistant</span>
          </h3>
          <Button 
            variant="ghost" 
            size="sm"
            onClick={() => setAiAssistantOpen(false)}
            className=""
          >
            <Icons.X />
          </Button>
        </div>
        <p className="text-sm text-muted-foreground mt-1">
          Contextual questions and creative prompts
        </p>
      </div>

      {/* Category Filters */}
      <div className="p-4 border-b">
        <div className="grid grid-cols-3 gap-2">
          {categories.map(category => (
            <button
              key={category.id}
              onClick={() => setActiveCategory(category.id)}
              className={`p-2 rounded text-xs font-medium transition-all duration-200 ${
                activeCategory === category.id 
                  ? 'bg-primary text-primary-foreground' 
                  : 'bg-muted hover:bg-muted-foreground/10'
              }`}
            >
              {category.label}
            </button>
          ))}
        </div>
      </div>

      <div className="flex-1 p-4 overflow-auto">
        <div className="space-y-3">
          {/* AI Status */}
          {isTyping && (
            <div className="bg-card p-3 rounded-lg border animate-pulse">
              <div className="flex items-center space-x-2">
                <div className="w-2 h-2 bg-primary rounded-full animate-pulse"></div>
                <span className="text-sm text-muted-foreground">AI is thinking...</span>
              </div>
            </div>
          )}

          {filteredSuggestions.map((suggestion, index) => (
            <div
              key={suggestion.id}
              className={`ai-suggestion ai-message cursor-pointer transition-all duration-300 ${
                selectedSuggestion?.id === suggestion.id ? 'bg-primary/10 border-primary' : ''
              }`}
              onClick={() => handleSuggestionClick(suggestion)}
              style={{ animationDelay: `${index * 0.1}s` }}
            >
              <div className="flex items-center justify-between mb-2">
                <span className="text-xs font-medium text-primary bg-primary/10 px-2 py-1 rounded-full">
                  {suggestion.category}
                </span>
                <div className="flex items-center space-x-1">
