          >
            Return to Writing
          </button>
          <button
            className="px-4 py-2 border border-white/20 rounded-md hover:bg-white/10 transition-colors"
            onClick={() => {
              // This could open a notification system or feedback form
              console.info('Get notified when this module is ready!');
            }}
          >
            Get Notified
          </button>
        </div>

        {/* Shortcut Hint */}
        {route.shortcut && (
          <p className="mt-6 text-xs text-white/40">
            Quick access: <kbd className="px-1 py-0.5 bg-white/10 rounded text-white/60">{route.shortcut}</kbd>
          </p>
        )}
      </div>
    </div>
  );
};

// Enhanced Navigation Component
const NavigationTabs = () => {
  const { currentRoute, navigate, activeRoutes, comingSoonRoutes } = useRouter();
  const Icons = window.Icons; // Use global Icons from app.js
  const cn = window.cn; // Use global cn utility from app.js

  return (
    <nav className="hidden md:flex space-x-2">
