          className={cn(
            'px-3 py-2 rounded-md text-sm font-medium transition-all duration-150 ease-in-out cursor-pointer border-0 bg-transparent text-foreground no-underline hover:bg-accent hover:text-accent-foreground',
            currentRoute.path === route.path ? 'bg-primary text-primary-foreground' : ''
