              &lt;div className=&quot;flex-1&quot;&gt;
                &lt;div className=&quot;flex items-center justify-between&quot;&gt;
                  &lt;h4 className=&quot;font-medium&quot;&gt;{character.name}&lt;/h4&gt;
                  &lt;span className=&quot;text-xs bg-secondary px-2 py-1 rounded&quot;&gt;{character.role}&lt;/span&gt;
