                    &lt;/Button&gt;
                  &lt;/div&gt;
                &lt;/div&gt;
              )}
            &lt;/div&gt;
          ))}
          {/* Story Health Analytics */}
          &lt;div className=&quot;mt-6 p-4 bg-card rounded-lg border animate-slide-up&quot;&gt;
            &lt;h4 className=&quot;font-medium mb-3 flex items-center&quot;&gt;
              &lt;Icons.TrendingUp /&gt;
              &lt;span className=&quot;ml-2&quot;&gt;Story Analytics&lt;/span&gt;
            &lt;/h4&gt;
            &lt;div className=&quot;space-y-3&quot;&gt;
              &lt;div className=&quot;flex justify-between items-center text-sm&quot;&gt;
                &lt;span&gt;Character Development&lt;/span&gt;
                &lt;div className=&quot;flex items-center space-x-2&quot;&gt;
                  &lt;div className=&quot;progress-ring&quot;&gt;
                    &lt;svg width=&quot;32&quot; height=&quot;32&quot; className=&quot;transform -rotate-90&quot;&gt;
                      &lt;circle
                        cx=&quot;16&quot; cy=&quot;16&quot; r=&quot;12&quot;
                        fill=&quot;none&quot;
                        stroke=&quot;currentColor&quot;
                        strokeWidth=&quot;3&quot;
                        className=&quot;text-muted opacity-20&quot;
                      /&gt;
                      &lt;circle
                        cx=&quot;16&quot; cy=&quot;16&quot; r=&quot;12&quot;
                        fill=&quot;none&quot;
                        stroke=&quot;currentColor&quot;
                        strokeWidth=&quot;3&quot;
                        strokeDasharray={`${85 * 0.75} ${100 * 0.75}`}
                        className=&quot;text-primary&quot;
                      /&gt;
                    &lt;/svg&gt;
                  &lt;/div&gt;
                  &lt;span className=&quot;text-primary font-medium&quot;&gt;85%&lt;/span&gt;
                &lt;/div&gt;
              &lt;/div&gt;
              &lt;div className=&quot;flex justify-between items-center text-sm&quot;&gt;
                &lt;span&gt;Plot Coherence&lt;/span&gt;
                &lt;div className=&quot;flex items-center space-x-2&quot;&gt;
                  &lt;div className=&quot;progress-ring&quot;&gt;
                    &lt;svg width=&quot;32&quot; height=&quot;32&quot; className=&quot;transform -rotate-90&quot;&gt;
                      &lt;circle
                        cx=&quot;16&quot; cy=&quot;16&quot; r=&quot;12&quot;
                        fill=&quot;none&quot;
                        stroke=&quot;currentColor&quot;
                        strokeWidth=&quot;3&quot;
                        className=&quot;text-muted opacity-20&quot;
                      /&gt;
                      &lt;circle
                        cx=&quot;16&quot; cy=&quot;16&quot; r=&quot;12&quot;
                        fill=&quot;none&quot;
                        stroke=&quot;currentColor&quot;
                        strokeWidth=&quot;3&quot;
                        strokeDasharray={`${72 * 0.75} ${100 * 0.75}`}
