              &lt;div className=&quot;flex justify-between items-center text-sm&quot;&gt;
                &lt;span&gt;World Building&lt;/span&gt;
                &lt;div className=&quot;flex items-center space-x-2&quot;&gt;
                  &lt;div className=&quot;progress-ring&quot;&gt;
                    &lt;svg width=&quot;32&quot; height=&quot;32&quot; className=&quot;transform -rotate-90&quot;&gt;
                      &lt;circle
                        cx=&quot;16&quot; cy=&quot;16&quot; r=&quot;12&quot;
                        fill=&quot;none&quot;
