// --- Components ---
// Button Component (shadcn-inspired)
const Button = ({ children, variant = &apos;default&apos;, size = &apos;default&apos;, className = &apos;&apos;, onClick, ...props }) =&gt; {
  const baseClasses = &apos;inline-flex items-center justify-center rounded-md text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50 cursor-pointer select-none transition-all duration-200 hover:scale-105 active:scale-95&apos;;
  const variants = {
    default: &apos;bg-primary text-primary-foreground hover:bg-primary/90&apos;,
    secondary: &apos;bg-secondary text-secondary-foreground hover:bg-secondary/80&apos;,
    ghost: &apos;hover:bg-accent hover:text-accent-foreground&apos;,
    outline: &apos;border border-input bg-background hover:bg-accent hover:text-accent-foreground&apos;
  };
  const sizes = {
    default: &apos;h-10 px-4 py-2&apos;,
    sm: &apos;h-9 rounded-md px-3&apos;,
    lg: &apos;h-11 rounded-md px-8&apos;
  };
  return (
    &lt;button 
      className={cn(baseClasses, variants[variant], sizes[size], className)}
      onClick={onClick}
      {...props}
    &gt;
      {children}
    &lt;/button&gt;
  );
};
// Card Component (shadcn-inspired)
const Card = ({ children, className = &apos;&apos;, onClick, ...props }) =&gt; (
  &lt;div className={cn(&apos;card&apos;, className)} onClick={onClick} {...props}&gt;
    {children}
  &lt;/div&gt;
);
// Progress Component
const Progress = ({ value, className = &apos;&apos; }) =&gt; (
  &lt;div className={cn(&apos;progress-bar&apos;, className)}&gt;
    &lt;div className=&quot;progress-fill&quot; style={{ width: `${value}%` }} /&gt;
  &lt;/div&gt;
);
// SpaceButton Component
const SpaceButton = ({ icon: Icon, label, active, space, onClick, className = &apos;&apos; }) =&gt; {
  const { navigate } = window.useRouter();
  const handleClick = () =&gt; {
    if (onClick) {
      onClick();
    } else {
      const routePath = `/${space.toLowerCase()}`;
      navigate(routePath);
    }
  };
  return (
    &lt;button
      onClick={handleClick}
      className={cn(
        &apos;inline-flex items-center space-x-2 px-3 py-2 rounded-md text-sm font-medium transition-all duration-150 ease-in-out cursor-pointer border-0 bg-transparent text-foreground no-underline hover:bg-accent hover:text-accent-foreground&apos;,
        active ? &apos;bg-primary text-primary-foreground&apos; : &apos;&apos;,
        className
      )}
    &gt;
      &lt;Icon className=&quot;w-4 h-4&quot; /&gt;
      &lt;span&gt;{label}&lt;/span&gt;
    &lt;/button&gt;
  );
};
