                    &lt;svg width=&quot;32&quot; height=&quot;32&quot; className=&quot;transform -rotate-90&quot;&gt;
                      &lt;circle
                        cx=&quot;16&quot; cy=&quot;16&quot; r=&quot;12&quot;
