// Utility functions for routing
function getRouteByPath(path) {
  return routes.find(route =&gt; route.path === path) || routes[0];
}
function getRouteByName(name) {
  return routes.find(route =&gt; route.name === name) || routes[0];
}
function getActiveRoutes() {
  return routes.filter(route =&gt; route.active);
}
function getComingSoonRoutes() {
  return routes.filter(route =&gt; route.comingSoon);
}
// Router context for state management
const RouterContext = createContext();
const RouterProvider = ({ children }) =&gt; {
  const [currentRoute, setCurrentRoute] = useState(() =&gt; getRouteByName(&apos;Writing&apos;));
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [routeHistory, setRouteHistory] = useState([]);
  const navigate = useCallback((pathOrRoute, options = {}) =&gt; {
    const route = typeof pathOrRoute === &apos;string&apos; 
      ? getRouteByPath(pathOrRoute) 
      : pathOrRoute;
    if (!route) {
      console.warn(&apos;Route not found:&apos;, pathOrRoute);
      return;
    }
    // Don&apos;t navigate if already on the same route
    if (route.path === currentRoute.path &amp;&amp; !options.force) {
      return;
    }
    // Check if route is coming soon
    if (route.comingSoon &amp;&amp; !options.allowComingSoon) {
      console.info(`${route.name} module is coming soon!`);
      return;
    }
    setIsTransitioning(true);
    // Update URL (for browser history)
    if (options.updateHistory !== false) {
      window.history.pushState(
        { route: route.path }, 
        `NarratingOS - ${route.name}`, 
        route.path
      );
    }
    // Update route history
    setRouteHistory(prev =&gt; [...prev.slice(-9), currentRoute.path]);
    setTimeout(() =&gt; {
      setCurrentRoute(route);
      setIsTransitioning(false);
    }, options.transitionDelay || 300);
  }, [currentRoute]);
  const goBack = useCallback(() =&gt; {
    if (routeHistory.length &gt; 0) {
      const previousPath = routeHistory[routeHistory.length - 1];
      const previousRoute = getRouteByPath(previousPath);
      if (previousRoute) {
        setRouteHistory(prev =&gt; prev.slice(0, -1));
        navigate(previousRoute, { updateHistory: false });
      }
    }
  }, [routeHistory, navigate]);
  // Initialize from URL on mount and handle browser navigation
  useEffect(() =&gt; {
    const initializeRoute = () =&gt; {
      const path = window.location.pathname || &apos;/writing&apos;;
      const route = getRouteByPath(path);
      if (route &amp;&amp; route.active) {
        setCurrentRoute(route);
      } else {
        // Fallback to writing if route is not active
        setCurrentRoute(getRouteByName(&apos;Writing&apos;));
        window.history.replaceState(null, &apos;&apos;, &apos;/writing&apos;);
      }
    };
    initializeRoute();
    // Handle browser back/forward
    const handlePopState = (event) =&gt; {
      const path = window.location.pathname || &apos;/writing&apos;;
      const route = getRouteByPath(path);
      if (route &amp;&amp; route.active) {
        setCurrentRoute(route);
      } else {
        navigate(getRouteByName(&apos;Writing&apos;), { updateHistory: false });
      }
    };
    window.addEventListener(&apos;popstate&apos;, handlePopState);
    return () =&gt; {
      window.removeEventListener(&apos;popstate&apos;, handlePopState);
    };
  }, [navigate]);
  // Keyboard shortcuts
  useEffect(() =&gt; {
    const handleKeyboard = (event) =&gt; {
      // Only handle shortcuts when no input is focused
      if (event.target.tagName === &apos;INPUT&apos; || event.target.tagName === &apos;TEXTAREA&apos;) {
        return;
      }
      const { metaKey, ctrlKey, shiftKey, key } = event;
      const isCmd = metaKey || ctrlKey;
      if (!isCmd) return;
      // Find route by shortcut
      let targetRoute = null;
      // Number shortcuts (⌘1-9, ⌘0)
      if (key &gt;= &apos;1&apos; &amp;&amp; key &lt;= &apos;9&apos;) {
        const index = parseInt(key) - 1;
        const activeRoutes = getActiveRoutes();
        if (activeRoutes[index]) {
          targetRoute = activeRoutes[index];
        }
      } else if (key === &apos;0&apos;) {
        // ⌘0 for last route
        const activeRoutes = getActiveRoutes();
        targetRoute = activeRoutes[activeRoutes.length - 1];
      }
      // Letter shortcuts
      else if (shiftKey) {
        switch (key.toLowerCase()) {
          case &apos;c&apos;:
            targetRoute = getRouteByPath(&apos;/collaboration&apos;);
            break;
          case &apos;a&apos;:
            targetRoute = getRouteByPath(&apos;/assets&apos;);
            break;
          case &apos;r&apos;:
            targetRoute = getRouteByPath(&apos;/analytics&apos;);
            break;
        }
      } else {
        switch (key.toLowerCase()) {
          case &apos;t&apos;:
            targetRoute = getRouteByPath(&apos;/templates&apos;);
            break;
        }
      }
      if (targetRoute) {
        event.preventDefault();
        if (targetRoute.active) {
          navigate(targetRoute);
        } else {
          // Show coming soon notification
          console.info(`${targetRoute.name} (${targetRoute.shortcut}) - Coming Soon!`);
        }
      }
    };
    document.addEventListener(&apos;keydown&apos;, handleKeyboard);
    return () =&gt; {
      document.removeEventListener(&apos;keydown&apos;, handleKeyboard);
    };
  }, [navigate]);
  const contextValue = {
    currentRoute,
    isTransitioning,
    navigate,
    goBack,
    routes,
    routeHistory,
    activeRoutes: getActiveRoutes(),
    comingSoonRoutes: getComingSoonRoutes()
  };
  return (
    &lt;RouterContext.Provider value={contextValue}&gt;
      {children}
    &lt;/RouterContext.Provider&gt;
  );
};
const useRouter = () =&gt; {
  const context = useContext(RouterContext);
  if (!context) {
    throw new Error(&apos;useRouter must be used within a RouterProvider&apos;);
  }
  return context;
};
